import React, { useState } from "react";

export default function NotificationList() {
  const [selected, setSelected] = useState(null); // popup mở thông báo chi tiết

  const notifications = [
    {
      title: "Nguyễn Văn A đã thích bài viết của bạn",
      detail: "Nguyễn Văn A đã bày tỏ cảm xúc với bài đăng bạn chia sẻ sáng nay.",
      time: "5 phút trước",
      img: "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png",
    },
    {
      title: "Trần Thị B đã bình luận: 'Rất hay!'",
      detail: "Bình luận này nằm trong bài viết 'Chia sẻ kinh nghiệm học ReactJS'.",
      time: "20 phút trước",
      img: "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png",
    },
    {
      title: "Lê Văn C đã gửi lời mời kết bạn",
      detail: "Bạn có thể xem hồ sơ của Lê Văn C để chấp nhận hoặc từ chối lời mời.",
      time: "1 giờ trước",
      img: "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png",
    },
    {
      title: "Phạm Thị D đã chia sẻ bài viết của bạn",
      detail: "Bài viết của bạn đang nhận được nhiều tương tác sau khi được chia sẻ.",
      time: "2 giờ trước",
      img: "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png",
    },
  ];

  const updates = [
    { title: "Cập nhật mới từ nhóm 'Lập trình Web'", time: "3 giờ trước" },
    { title: "Workshop ReactJS diễn ra vào thứ 6", time: "1 ngày trước" },
    { title: "Ứng dụng đã ra phiên bản mới!", time: "2 ngày trước" },
  ];

  return (
    <div className="flex gap-6 relative">
      {/* Danh sách thông báo */}
      <div className="flex-1 flex flex-col gap-4">
        <h2 className="text-2xl font-bold mb-3">Thông báo gần đây</h2>
        {notifications.map((item, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#E2F0FF] p-3 rounded-lg shadow-sm"
          >
            <img
              src={item.img}
              alt="avatar"
              className="w-[80px] h-[80px] rounded-full object-cover"
            />
            <div className="flex-1">
              <p className="text-lg text-black">{item.title}</p>
              <span className="text-gray-600 text-sm">{item.time}</span>
            </div>
            <button
              className="bg-[#88BCF8] text-white px-4 py-1 rounded-lg hover:bg-[#63A4F8]"
              onClick={() => setSelected(item)}
            >
              Xem chi tiết
            </button>
          </div>
        ))}
      </div>

      {/* Cột tin cập nhật bên phải */}
      <div className="w-[300px] flex flex-col gap-3">
        <h2 className="text-2xl font-bold mb-3">Tin cập nhật</h2>
        {updates.map((item, idx) => (
          <div
            key={idx}
            className="flex flex-col gap-1 bg-[#F6FAFF] p-3 rounded-lg shadow-sm"
          >
            <p className="text-black text-base font-medium">{item.title}</p>
            <span className="text-gray-500 text-sm">{item.time}</span>
          </div>
        ))}
      </div>

      {/* Popup xem chi tiết */}
      {selected && (
        <div className="fixed inset-0 bg-black/30 flex justify-center items-center z-50">
          <div className="bg-white rounded-xl shadow-lg w-[400px] p-6 relative">
            <h3 className="text-2xl font-semibold mb-3 text-[#0056A6]">
              Chi tiết thông báo
            </h3>
            <p className="text-black mb-2">{selected.detail}</p>
            <span className="text-gray-500 text-sm">{selected.time}</span>

            <button
              onClick={() => setSelected(null)}
              className="absolute top-3 right-4 text-gray-500 hover:text-black text-xl"
            >
              ✕
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
